
(function instalarModaisVetCore(){
  if (window.vetcoreModaisInstalados) return;
  window.vetcoreModaisInstalados = true;

  function garantirModal(){
    let modal = document.getElementById('vetcoreModalSistema');
    if (modal) return modal;
    modal = document.createElement('div');
    modal.id = 'vetcoreModalSistema';
    modal.className = 'vetcore-modal-sistema oculto';
    modal.innerHTML = `
      <div class="vetcore-modal-card" role="dialog" aria-modal="true" aria-labelledby="vetcoreModalTitulo">
        <div class="vetcore-modal-icone" id="vetcoreModalIcone">!</div>
        <h3 id="vetcoreModalTitulo">Aviso</h3>
        <div id="vetcoreModalMensagem" class="vetcore-modal-mensagem"></div>
        <input id="vetcoreModalInput" class="vetcore-modal-input oculto" type="text" />
        <div class="vetcore-modal-acoes">
          <button type="button" id="vetcoreModalCancelar" class="btn-secundario oculto">Cancelar</button>
          <button type="button" id="vetcoreModalOk" class="btn-verde">OK</button>
        </div>
      </div>`;
    document.body.appendChild(modal);
    return modal;
  }

  function quebrarLinhas(texto){
    return String(texto ?? '').replace(/\n/g, '<br>');
  }

  window.vcModal = function vcModal(opcoes = {}){
    return new Promise(resolve => {
      const modal = garantirModal();
      const titulo = document.getElementById('vetcoreModalTitulo');
      const msg = document.getElementById('vetcoreModalMensagem');
      const icone = document.getElementById('vetcoreModalIcone');
      const input = document.getElementById('vetcoreModalInput');
      const ok = document.getElementById('vetcoreModalOk');
      const cancelar = document.getElementById('vetcoreModalCancelar');

      titulo.textContent = opcoes.titulo || 'Aviso';
      msg.innerHTML = quebrarLinhas(opcoes.mensagem || '');
      icone.textContent = opcoes.icone || (opcoes.tipo === 'confirm' ? '?' : '!');
      ok.textContent = opcoes.textoOk || 'OK';
      cancelar.textContent = opcoes.textoCancelar || 'Cancelar';

      const usarInput = opcoes.tipo === 'prompt';
      input.classList.toggle('oculto', !usarInput);
      input.value = opcoes.valorPadrao || '';

      const usarCancelar = opcoes.tipo === 'confirm' || opcoes.tipo === 'prompt';
      cancelar.classList.toggle('oculto', !usarCancelar);
      modal.classList.remove('oculto');

      const limpar = () => {
        ok.onclick = null;
        cancelar.onclick = null;
        document.removeEventListener('keydown', tecla);
        modal.classList.add('oculto');
      };
      const finalizar = valor => { limpar(); resolve(valor); };
      const tecla = e => {
        if (e.key === 'Escape' && usarCancelar) finalizar(opcoes.tipo === 'prompt' ? null : false);
        if (e.key === 'Enter') finalizar(usarInput ? input.value : true);
      };
      ok.onclick = () => finalizar(usarInput ? input.value : true);
      cancelar.onclick = () => finalizar(opcoes.tipo === 'prompt' ? null : false);
      document.addEventListener('keydown', tecla);
      setTimeout(() => (usarInput ? input : ok).focus(), 50);
    });
  };

  window.vcAlert = function vcAlert(mensagem, titulo = 'Aviso'){
    return window.vcModal({ tipo: 'alert', titulo, mensagem, icone: '!' });
  };
  window.vcConfirm = function vcConfirm(mensagem, titulo = 'Confirmar'){
    return window.vcModal({ tipo: 'confirm', titulo, mensagem, icone: '?', textoOk: 'Confirmar', textoCancelar: 'Cancelar' });
  };
  window.vcPrompt = function vcPrompt(mensagem, valorPadrao = '', titulo = 'Preencher informação'){
    return window.vcModal({ tipo: 'prompt', titulo, mensagem, valorPadrao, icone: '✎', textoOk: 'Salvar', textoCancelar: 'Cancelar' });
  };

  window.alert = function(mensagem){ window.vcAlert(mensagem); };
})();


function vetcoreLimparClinicasInexistentesDosVinculos() {
  try {
    const cfg = obterConfiguracoesSistema();
    const existentes = new Set(Object.keys((cfg && cfg.clinicas) || {}));

    let usuarios = obterUsuariosPermitidos();
    let mudouUsuarios = false;
    usuarios = usuarios.map(u => {
      const copia = { ...u };
      if (Array.isArray(copia.clinicasVinculadas)) {
        const filtradas = copia.clinicasVinculadas.filter(c => existentes.has(c));
        if (filtradas.length !== copia.clinicasVinculadas.length) {
          copia.clinicasVinculadas = filtradas;
          mudouUsuarios = true
        }
      }
      if (copia.clinicaVinculada && !existentes.has(copia.clinicaVinculada)) {
        copia.clinicaVinculada = "";
        mudouUsuarios = true
      }
      return copia;
    });
    if (mudouUsuarios) salvarUsuariosPermitidos(usuarios);

    let clientes = [];
    try { clientes = JSON.parse(localStorage.getItem("vetcoreClientesMestre")) || []; } catch(e) {}
    let mudouClientes = false;
    clientes = clientes.map(c => {
      const copia = { ...c };
      if (Array.isArray(copia.clinicasVinculadas)) {
        const filtradas = copia.clinicasVinculadas.filter(x => existentes.has(x));
        if (filtradas.length !== copia.clinicasVinculadas.length) {
          copia.clinicasVinculadas = filtradas;
          mudouClientes = true;
        }
      }
      return copia;
    });
    if (mudouClientes) localStorage.setItem("vetcoreClientesMestre", JSON.stringify(clientes));
  } catch (e) {}
}

function vetcoreUsuarioEhMasterSeguro(email) {
  const e = (email || "").trim().toLowerCase();
  return ["admin"].includes(e);
}

function vetcoreUsuarioAtualSeguro() {
  const email = (localStorage.getItem("usuarioLogado") || "").trim().toLowerCase();
  const usuarios = obterUsuariosPermitidos();
  return usuarios.find(u => ((u.usuario || "").trim().toLowerCase() === email)) || null;
}

function vetcoreGarantirClinicaNoConfigSeguro(nomeClinica) {
  try {
    const nome = (nomeClinica || "").trim();
    if (!nome) return;
    const cfg = obterConfiguracoesSistema();
    if (!cfg.clinicas) cfg.clinicas = {};
    if (!cfg.clinicas[nome]) {
      cfg.clinicas[nome] = nome;
      salvarConfiguracoesSistemaStorage(cfg);
    }
  } catch (e) {}
}

function vetcoreSincronizarClinicaDoUsuario() {
  const atual = vetcoreUsuarioAtualSeguro();
  if (!atual || vetcoreUsuarioEhMasterSeguro(atual.usuario || "")) return atual;

  let clientes = [];
  try { clientes = JSON.parse(localStorage.getItem("vetcoreClientesMestre")) || []; } catch(e) {}
  const email = (atual.usuario || "").trim().toLowerCase();

  const cliente = clientes.find(c =>
    ((c.login || "").trim().toLowerCase() === email) ||
    ((c.email || "").trim().toLowerCase() === email)
  );

  const unidades = [];
  function addUnidade(chave) {
    const c = (chave || "").trim();
    if (c && !unidades.includes(c)) unidades.push(c);
  }

  if (cliente) {
    if (Array.isArray(cliente.clinicasVinculadas)) {
      cliente.clinicasVinculadas.forEach(addUnidade);
    }
  }

  addUnidade(atual.clinicaVinculada);
  if (Array.isArray(atual.clinicasVinculadas)) {
    atual.clinicasVinculadas.forEach(addUnidade);
  }

  unidades.forEach(chave => vetcoreGarantirClinicaNoConfigSeguro(chave));

  const principal = unidades[0] || atual.clinicaVinculada || "";
  const precisaAtualizar =
    principal !== (atual.clinicaVinculada || "") ||
    JSON.stringify(unidades) !== JSON.stringify(Array.isArray(atual.clinicasVinculadas) ? atual.clinicasVinculadas : []);

  if (precisaAtualizar) {
    const usuarios = obterUsuariosPermitidos();
    const idx = usuarios.findIndex(u => ((u.usuario || "").trim().toLowerCase() === email));
    if (idx >= 0) {
      usuarios[idx] = { ...usuarios[idx], clinicaVinculada: principal, clinicasVinculadas: unidades };
      salvarUsuariosPermitidos(usuarios);
      return usuarios[idx];
    }
  }

  return { ...atual, clinicaVinculada: principal, clinicasVinculadas: unidades.length ? unidades : (atual.clinicasVinculadas || []) };
}

function vetcoreClinicasPermitidasSeguro() {
  vetcoreLimparClinicasInexistentesDosVinculos();
  const config = obterConfiguracoesSistema();
  const todas = Object.keys((config && config.clinicas) || {});
  const atual = vetcoreSincronizarClinicaDoUsuario();

  if (!atual) return todas;
  if (vetcoreUsuarioEhMasterSeguro(atual.usuario || "")) return todas;

  const vinculadas = [];
  if (Array.isArray(atual.clinicasVinculadas)) {
    atual.clinicasVinculadas.forEach(chave => {
      const c = (chave || "").trim();
      if (c && !vinculadas.includes(c)) vinculadas.push(c);
    });
  }
  if (atual.clinicaVinculada) {
    const c = (atual.clinicaVinculada || "").trim();
    if (c && !vinculadas.includes(c)) vinculadas.unshift(c);
  }

  vinculadas.forEach(chave => vetcoreGarantirClinicaNoConfigSeguro(chave));
  return vinculadas;
}


