function normalizarChavePerfilVetCore(perfil) {
  const p = (perfil || "").toLowerCase().normalize("NFD").replace(/[\u0300-\u036f]/g, "").trim();
  if (p.includes("admin")) return "admin";
  if (p.includes("gest")) return "gestor";
  if (p.includes("recep")) return "recepcao";
  if (p.includes("vet")) return "veterinario";
  if (p.includes("financ")) return "financeiro";
  if (p.includes("atend")) return "atendente";
  if (p.includes("leitura") || p.includes("somente")) return "leitura";
  return p && perfisVetCore[p] ? p : "atendente";
}

function obterPerfilVetCore(perfil) {
  const chave = normalizarChavePerfilVetCore(perfil);
  return perfisVetCore[chave] || perfisVetCore.atendente;
}

