function obterConfiguracoesSistema() {
  const padrao = {
    nomeSistema: "VetCore",
    clinicas: {},
    logoDataUrl: "",
    clinicLogoDataUrl: `data:image/png;base64,`,
    enderecoClinica: "",
    cnpjClinica: "",
    contatoClinica: ""
  };

  const salvo = JSON.parse(localStorage.getItem("configuracoesSistema")) || {};
  const config = {
    ...padrao,
    ...salvo,
    clinicas: {
      ...padrao.clinicas,
      ...(salvo.clinicas || {})
    }
  };

  if (!config.nomeSistema || /bicho\s*feliz|agenda\s*cl[ií]nica/i.test(config.nomeSistema)) {
    config.nomeSistema = "VetCore";
    salvarConfiguracoesSistemaStorage(config);
  }

  return config;
}

function salvarConfiguracoesSistemaStorage(config) {
  localStorage.setItem("configuracoesSistema", JSON.stringify(config));
}


function vetcoreCorrigirClinicasLegadas() {
  const config = obterConfiguracoesSistema();
  let mudou = false;

  Object.keys(config.clinicas || {}).forEach(chave => {
    const nomeAtual = (config.clinicas[chave] || "").toString();
    if (/bicho\s*feliz/i.test(nomeAtual) || /bicho\s*feliz/i.test(chave)) {
      config.clinicas[chave] = `Clínica ${chave}`;
      mudou = true;
    }
  });

  if (mudou) {
    salvarConfiguracoesSistemaStorage(config);
  }
}

function vetcoreNormalizarAgendamentosCompareceu() {
  const lista = obterAgendamentos().map(item => {
    if (item && item.atendimentoStatus === "compareceu") return item;
    return { ...item, atendimentoStatus: item.atendimentoStatus || "" };
  });
  salvarAgendamentos(lista);
}

function marcarCompareceu(id) {
  const lista = obterAgendamentos();
  const indice = lista.findIndex(item => item.id === id);
  if (indice === -1) return;

  lista[indice] = {
    ...lista[indice],
    atendimentoStatus: lista[indice].atendimentoStatus === "compareceu" ? "" : "compareceu"
  };

  salvarAgendamentos(lista);

  try { atualizarPainelAgendaDia(); } catch(e) {}
  try { renderizarAgendamentosVisualizacao(); } catch(e) {}
  try { carregarListaAgendamentos(); } catch(e) {}
}

function podeMarcarCompareceu(agendamento) {
  if (!agendamento) return false;
  return normalizarServico(agendamento.servico) !== "castracao";
}

function obterClasseCompareceuAgendamento(agendamento) {
  return agendamento && agendamento.atendimentoStatus === "compareceu" ? " status-compareceu-cliente" : "";
}

function botaoCompareceuHtml(agendamento) {
  if (!podeMarcarCompareceu(agendamento)) return "";
  const ativo = agendamento && agendamento.atendimentoStatus === "compareceu";
  return `<button class="btn-compareceu btn-excluir-agendamento${ativo ? ' ativo' : ''}" onclick="marcarCompareceu(${agendamento.id})">${ativo ? '✓ Compareceu' : 'Compareceu'}</button>`;
}


function obterClientesMestreSeguro() {
  try {
    return JSON.parse(localStorage.getItem("vetcoreClientesMestre")) || [];
  } catch (e) {
    return [];
  }
}

function obterClienteMestrePorClinica(nomeClinica) {
  const chave = (nomeClinica || "").trim().toLowerCase();
  if (!chave) return null;
  return obterClientesMestreSeguro().find(item => {
    const principal = (item.nomeClinica || "").trim().toLowerCase();
    const unidades = Array.isArray(item.clinicasVinculadas) ? item.clinicasVinculadas : [];
    const unidadeVinculada = unidades.some(unidade => (unidade || "").trim().toLowerCase() === chave);
    return principal === chave || unidadeVinculada;
  }) || null;
}

function obterClinicaPrincipalDoCliente(nomeClinicaOuUnidade) {
  const cliente = obterClienteMestrePorClinica(nomeClinicaOuUnidade);
  return (cliente && cliente.nomeClinica) ? cliente.nomeClinica : (nomeClinicaOuUnidade || "");
}

function obterResumoPlanoCliente(nomeClinicaOuUnidade) {
  const cliente = obterClienteMestrePorClinica(nomeClinicaOuUnidade);
  const plano = ((cliente && cliente.plano) || "profissional").toUpperCase();
  const status = ((cliente && cliente.status) || "ativo").toUpperCase();
  return { cliente, plano, status };
}

function vetcoreStatusBloqueiaAcesso(status) {
  return ["vencido", "suspenso", "cancelado"].includes((status || "").trim().toLowerCase());
}

function vetcoreMensagemBloqueioClinica(nomeClinica) {
  const cliente = obterClienteMestrePorClinica(nomeClinica);
  if (!cliente) return "";
  const status = (cliente.status || "").trim().toLowerCase();
  const vencimento = cliente.vencimento ? ` Vencimento: ${cliente.vencimento}.` : "";
  if (status === "vencido") return `Acesso bloqueado para esta clínica porque o plano está vencido.${vencimento}`;
  if (status === "suspenso") return "Acesso bloqueado para esta clínica porque o cadastro está suspenso.";
  if (status === "cancelado") return "Acesso bloqueado para esta clínica porque o cadastro foi cancelado.";
  return "";
}

function vetcoreClinicaTemAcessoLiberado(nomeClinica) {
  return !vetcoreMensagemBloqueioClinica(nomeClinica);
}

function obterUsuariosPermitidos() {
  const salvos = JSON.parse(localStorage.getItem("usuariosSistema")) || [];
  if (!Array.isArray(salvos) || !salvos.length) return [...usuariosPadrao];

  const mapa = new Map();
  [...usuariosPadrao, ...salvos].forEach(item => {
    const chave = ((item && item.usuario) || "").trim().toLowerCase();
    if (!chave) return;
    mapa.set(chave, { ...item });
  });

  return Array.from(mapa.values());
}

function salvarUsuariosPermitidos(lista) {
  localStorage.setItem("usuariosSistema", JSON.stringify(lista));
}



function garantirUsuarioMasterWilliam() {
  // Versão limpa de produção: mantém apenas o administrador padrão quando não há usuários cadastrados.
  const usuarios = JSON.parse(localStorage.getItem("usuariosSistema")) || [];
  if (!usuarios.length) {
    localStorage.setItem("usuariosSistema", JSON.stringify(usuariosPadrao));
  }
}

function migrarUsuariosAntigosParaEmail() {
  // Não migrar o usuário admin padrão na versão limpa.
  const usuarios = JSON.parse(localStorage.getItem("usuariosSistema")) || [];
  if (!usuarios.length) return;
  localStorage.setItem("usuariosSistema", JSON.stringify(usuarios));
}


let usuarioConfiguracaoSelecionadoIndex = null;

function obterPermissoesPadraoPorPerfil(perfil) {
  return { ...(obterPerfilVetCore(perfil).permissoes || {}) };
}

function garantirEstruturaUsuarios() {
  const usuarios = obterUsuariosPermitidos().map(item => ({
    ...item,
    perfil: item.perfil || "usuário",
    permissoes: { ...obterPermissoesPadraoPorPerfil(item.perfil), ...(item.permissoes || {}) }
  }));
  salvarUsuariosPermitidos(usuarios);
  return usuarios;
}

function obterUsuarioAtualObjeto() {
  const usuario = obterUsuarioLogado();
  return obterUsuariosPermitidos().find(item => item.usuario === usuario) || null;
}

function obterUsuarioAtualObjetoNormalizado() {
  const usuario = (obterUsuarioLogado() || "").trim().toLowerCase();
  return obterUsuariosPermitidos().find(item => ((item.usuario || "").trim().toLowerCase() === usuario)) || null;
}

function usuarioEhMasterVetCore(usuarioObj) {
  const email = ((usuarioObj && usuarioObj.usuario) || "").trim().toLowerCase();
  return [
    "admin"
  ].includes(email);
}

function obterClinicasPermitidasParaUsuarioLogado() {
  return vetcoreClinicasPermitidasSeguro();
}

function usuarioLogadoEhClienteRestrito() {
  const usuarioObj = obterUsuarioAtualObjetoNormalizado();
  return !!(usuarioObj && !usuarioEhMasterVetCore(usuarioObj) && usuarioObj.clinicaVinculada);
}

function obterClinicaUnicaDoUsuarioLogado() {
  const usuarioObj = obterUsuarioAtualObjetoNormalizado();
  if (!usuarioObj || usuarioEhMasterVetCore(usuarioObj)) return "";
  return usuarioObj.clinicaVinculada || "";
}

function autoSelecionarClinicaUsuarioVinculado() {
  const permitidas = vetcoreClinicasPermitidasSeguro();
  if (permitidas.length === 1 && vetcoreClinicaTemAcessoLiberado(permitidas[0])) {
    localStorage.setItem("clinicaSelecionada", permitidas[0]);
    atualizarMenu();
    mostrarTela("telaMenu");
    return true;
  }
  return false;
}

function temPermissao(chave) {
  const usuarioAtual = obterUsuarioAtualObjeto();
  if (!usuarioAtual) return false;
  const permissoes = { ...obterPermissoesPadraoPorPerfil(usuarioAtual.perfil), ...(usuarioAtual.permissoes || {}) };
  return permissoes[chave] === true;
}

function aplicarPermissoesNoMenu() {
  const mapa = [
    ["btnMenuAgendar", "agendar"],
    ["btnMenuVisualizar", "visualizar"],
    ["btnMenuRelatorios", "relatorios"],
    ["btnMenuLiberacao", "bloqueioData"],
    ["btnMenuFecharData", "bloqueioData"],
    ["btnMenuFecharRecorrente", "bloqueioRecorrente"],
    ["btnMenuConfiguracoes", "configuracoes"]
  ];

  mapa.forEach(([id, permissao]) => {
    const el = document.getElementById(id);
    if (el) el.style.display = temPermissao(permissao) ? "" : "none";
  });
}

function descreverPermissoes(permissoes) {
  const labels = [];
  if (permissoes.agendar) labels.push("Agendar");
  if (permissoes.visualizar) labels.push("Visualizar");
  if (permissoes.relatorios) labels.push("Relatórios");
  if (permissoes.bloqueioData) labels.push("Bloq. data");
  if (permissoes.bloqueioRecorrente) labels.push("Bloq. recorrente");
  if (permissoes.agendaExtra) labels.push("Agenda extra");
  if (permissoes.configuracoes) labels.push("Config.");
  if (permissoes.editarAgendamento) labels.push("Editar");
  if (permissoes.excluirAgendamento) labels.push("Excluir");
  if (permissoes.confirmarAgendamento) labels.push("Confirmar");
  if (permissoes.cadastrarUsuarios) labels.push("Usuários");
  return labels.join(", ") || "-";
}

function carregarPermissoesUsuarioNaTela(index) {
  const usuarios = obterUsuariosPermitidos();
  const item = usuarios[index];
  if (!item) return;

  usuarioConfiguracaoSelecionadoIndex = index;
  document.getElementById("usuarioSelecionadoPermissoes").innerText = `Usuário selecionado: ${item.usuario} (${item.perfil || "-"})`;

  const p = { ...obterPermissoesPadraoPorPerfil(item.perfil), ...(item.permissoes || {}) };
  document.getElementById("permAgendar").checked = !!p.agendar;
  document.getElementById("permVisualizar").checked = !!p.visualizar;
  document.getElementById("permRelatorios").checked = !!p.relatorios;
  document.getElementById("permBloqueioData").checked = !!p.bloqueioData;
  document.getElementById("permBloqueioRecorrente").checked = !!p.bloqueioRecorrente;
  document.getElementById("permAgendaExtra").checked = !!p.agendaExtra;
  document.getElementById("permConfiguracoes").checked = !!p.configuracoes;
  document.getElementById("permEditarAgendamento").checked = !!p.editarAgendamento;
  document.getElementById("permExcluirAgendamento").checked = !!p.excluirAgendamento;
  document.getElementById("permConfirmarAgendamento").checked = !!p.confirmarAgendamento;
  document.getElementById("permCadastrarUsuarios").checked = !!p.cadastrarUsuarios;
}

function salvarPermissoesUsuarioSelecionado() {
  if (usuarioConfiguracaoSelecionadoIndex === null) {
    alert("Selecione um usuário na lista.");
    return;
  }

  const usuarios = obterUsuariosPermitidos();
  const item = usuarios[usuarioConfiguracaoSelecionadoIndex];
  if (!item) return;

  item.permissoes = {
    agendar: document.getElementById("permAgendar").checked,
    visualizar: document.getElementById("permVisualizar").checked,
    relatorios: document.getElementById("permRelatorios").checked,
    bloqueioData: document.getElementById("permBloqueioData").checked,
    bloqueioRecorrente: document.getElementById("permBloqueioRecorrente").checked,
    agendaExtra: document.getElementById("permAgendaExtra").checked,
    configuracoes: document.getElementById("permConfiguracoes").checked,
    editarAgendamento: document.getElementById("permEditarAgendamento").checked,
    excluirAgendamento: document.getElementById("permExcluirAgendamento").checked,
    confirmarAgendamento: document.getElementById("permConfirmarAgendamento").checked,
    cadastrarUsuarios: document.getElementById("permCadastrarUsuarios").checked
  };

  salvarUsuariosPermitidos(usuarios);
  renderizarListaUsuariosConfiguracao();
  aplicarPermissoesNoMenu();
  alert("Permissões salvas com sucesso.");
}

function obterNomeClinicaExibicao(chaveClinica) {
  const config = obterConfiguracoesSistema();
  return config.clinicas[chaveClinica] || chaveClinica;
}

function aplicarConfiguracoesNaInterface() {
  const config = obterConfiguracoesSistema();

  document.title = config.nomeSistema || "VetCore";
  const tituloPagina = document.getElementById("tituloPagina");
  if (tituloPagina) tituloPagina.innerText = config.nomeSistema || "VetCore";

  const subtituloLogin = document.getElementById("subtituloLogin");
  if (subtituloLogin) {
    subtituloLogin.innerText = "Entre para acessar " + (config.nomeSistema || "VetCore");
  }

  const clinicLogoSrc = config.clinicLogoDataUrl || "./logo clinica.png";

  document.querySelectorAll(".logo").forEach(img => {
    img.style.display = "";
    img.src = clinicLogoSrc;
    img.onerror = function() { this.style.display = "none"; };
  });

  const preview = document.getElementById("previewLogoConfiguracao");
  if (preview) {
    preview.src = clinicLogoSrc;
    preview.style.display = "block";
  }

  const dashboardClinicLogo = document.getElementById("dashboardClinicLogo");
  if (dashboardClinicLogo) {
    dashboardClinicLogo.src = clinicLogoSrc;
    dashboardClinicLogo.style.display = "block";
  }

  const dashboardLogoPainel = document.getElementById("dashboardLogoPainel");
  if (dashboardLogoPainel) {
    dashboardLogoPainel.src = clinicLogoSrc;
    dashboardLogoPainel.style.display = "block";
  }

  const clinicaAtual = obterClinicaSelecionada();
  const nomeAtual = clinicaAtual ? obterNomeClinicaExibicao(clinicaAtual) : "Nome da clínica";
  const dashboardClinicNome = document.getElementById("dashboardClinicNome");
  if (dashboardClinicNome) {
    dashboardClinicNome.innerText = clinicaAtual ? obterNomeClinicaExibicao(clinicaAtual) : "Clínica";
  }

  const footerNomeClinica = document.getElementById("footerNomeClinica");
  const footerEndereco = document.getElementById("footerEndereco");
  const footerCnpj = document.getElementById("footerCnpj");
  const footerContato = document.getElementById("footerContato");
  const footerSistemaNome = document.getElementById("footerSistemaNome");

  if (footerNomeClinica) footerNomeClinica.innerText = nomeAtual;
  if (footerEndereco) footerEndereco.innerText = config.enderecoClinica || "Endereço da clínica";
  if (footerCnpj) footerCnpj.innerText = "CNPJ: " + (config.cnpjClinica || "00.000.000/0000-00");
  if (footerContato) footerContato.innerText = "Contato: " + (config.contatoClinica || "(00) 00000-0000");
  if (footerSistemaNome) footerSistemaNome.innerText = config.nomeSistema || "VetCore";

  document.querySelectorAll('[data-vetcore-system-name]').forEach(el => {
    el.innerText = config.nomeSistema || "VetCore";
  });
}

function abrirTelaConfiguracoes() {
  if (!temPermissao("configuracoes")) { alert("Você não tem permissão para acessar Configurações."); return; }
  carregarTelaConfiguracoes();
  mostrarTela("telaConfiguracoes");
  setTimeout(aplicarClinicaVinculadaNosCampos, 50);
}

function carregarTelaConfiguracoes() {
  const config = obterConfiguracoesSistema();
  const atualCfg = vetcoreSincronizarClinicaDoUsuario ? vetcoreSincronizarClinicaDoUsuario() : null;
  const restritoCfg = !!(atualCfg && !vetcoreUsuarioEhMasterSeguro(atualCfg.usuario || ""));
  const campoNovaClinica = document.getElementById("novaClinicaChave");
  const blocoNovaClinica = campoNovaClinica ? campoNovaClinica.closest(".config-bloco") : null;
  // Cliente comum também pode cadastrar UNIDADES da própria clínica.
  // Escondemos só o identificador interno e deixamos o sistema gerar a chave.
  if (blocoNovaClinica) blocoNovaClinica.style.display = "";
  if (campoNovaClinica) {
    campoNovaClinica.style.display = restritoCfg ? "none" : "";
    if (restritoCfg) campoNovaClinica.value = "";
  }
  document.getElementById("cfgNomeSistema").value = config.nomeSistema || "VetCore";
  const end = document.getElementById("cfgEnderecoClinica");
  const cnpj = document.getElementById("cfgCnpjClinica");
  const contato = document.getElementById("cfgContatoClinica");
  if (end) end.value = config.enderecoClinica || "";
  if (cnpj) cnpj.value = config.cnpjClinica || "";
  if (contato) contato.value = config.contatoClinica || "";

  const preview = document.getElementById("previewLogoConfiguracao");
  if (preview) {
    preview.src = config.clinicLogoDataUrl || "./logo clinica.png";
    preview.style.display = "block";
  }

  renderizarListaClinicasConfiguracao();
  popularSelectClinicasConfiguracao("profissionalClinica");
  popularSelectClinicasConfiguracao("filtroProfissionaisClinica");
  renderizarServicosProfissionalConfiguracao();
  atualizarPreviewHorariosProfissional();
  renderizarListaProfissionaisConfiguracao();
  renderizarListaUsuariosConfiguracao();
  preencherPermissoesPerfilSelecionado();
  renderizarTelaSelecaoClinicas();
}

function salvarConfiguracoesSistema() {
  const atual = obterConfiguracoesSistema();
  const novoConfig = {
    ...atual,
    nomeSistema: document.getElementById("cfgNomeSistema").value.trim() || "VetCore",
    enderecoClinica: document.getElementById("cfgEnderecoClinica") ? document.getElementById("cfgEnderecoClinica").value.trim() : (atual.enderecoClinica || ""),
    cnpjClinica: document.getElementById("cfgCnpjClinica") ? document.getElementById("cfgCnpjClinica").value.trim() : (atual.cnpjClinica || ""),
    contatoClinica: document.getElementById("cfgContatoClinica") ? document.getElementById("cfgContatoClinica").value.trim() : (atual.contatoClinica || "")
  };

  salvarConfiguracoesSistemaStorage(novoConfig);
  aplicarConfiguracoesNaInterface();
  atualizarMenu();
  alert("Configurações salvas com sucesso.");
}

function aoSelecionarLogoConfiguracao(event) {
  const arquivo = event.target.files?.[0];
  if (!arquivo) return;

  const reader = new FileReader();
  reader.onload = function(e) {
    const config = obterConfiguracoesSistema();
    config.clinicLogoDataUrl = e.target.result;
    salvarConfiguracoesSistemaStorage(config);
    aplicarConfiguracoesNaInterface();
  };
  reader.readAsDataURL(arquivo);
}

function restaurarLogoPadrao() {
  const config = obterConfiguracoesSistema();
  config.clinicLogoDataUrl = "";
  salvarConfiguracoesSistemaStorage(config);
  aplicarConfiguracoesNaInterface();
  alert("Logo da clínica restaurado.");
}


function slugClinica(texto) {
  return normalizar(texto).replace(/[^a-z0-9]+/g, "-").replace(/^-+|-+$/g, "");
}

function obterProfissionaisSalvos() {
  return JSON.parse(localStorage.getItem("veterinariosPorClinica")) || {};
}

function salvarProfissionaisStorage() {
  localStorage.setItem("veterinariosPorClinica", JSON.stringify(veterinariosPorClinica));
}

function garantirEstruturaProfissionais() {
  const salvos = obterProfissionaisSalvos();
  const config = obterConfiguracoesSistema();
  const chaves = new Set([
    ...Object.keys(veterinariosPadraoPorClinica || {}),
    ...Object.keys(salvos || {}),
    ...Object.keys((config && config.clinicas) || {})
  ]);

  const atualizados = {};
  chaves.forEach(chave => {
    const listaSalva = Array.isArray(salvos[chave]) ? salvos[chave] : null;
    const listaPadrao = Array.isArray(veterinariosPadraoPorClinica[chave]) ? veterinariosPadraoPorClinica[chave] : [];
    atualizados[chave] = JSON.parse(JSON.stringify(listaSalva || listaPadrao || []));
  });

  veterinariosPorClinica = atualizados;
  salvarProfissionaisStorage();
}

function renderizarTelaSelecaoClinicas() {
  const grid = document.getElementById("clinicaGridDinamica");
  if (!grid) return;

  vetcoreLimparClinicasInexistentesDosVinculos();

  const config = obterConfiguracoesSistema();
  const permitidas = [...new Set(vetcoreClinicasPermitidasSeguro())];
  const clinicas = permitidas
    .filter(chave => config.clinicas && config.clinicas[chave])
    .map(chave => [chave, config.clinicas[chave]]);

  grid.innerHTML = "";

  if (!clinicas.length) {
    grid.innerHTML = '<div class="config-card">Nenhuma clínica disponível para este usuário.</div>';
    return;
  }

  clinicas.forEach(([chave, nome]) => {
    const bloqueio = vetcoreMensagemBloqueioClinica(chave);
    const resumoPlano = obterResumoPlanoCliente(chave);
    const status = resumoPlano.status;
    const plano = resumoPlano.plano;
    const botao = document.createElement("button");
    botao.className = "clinic-card-ultra" + (bloqueio ? " clinic-card-bloqueado" : "");
    botao.type = "button";
    botao.disabled = !!bloqueio;
    botao.onclick = () => selecionarClinica(chave);
    botao.innerHTML = `
      <strong>${nome || chave}</strong>
      <span>${bloqueio || "Acesse agenda, bloqueios, atendimentos e gestão da unidade."}</span>
      <span style="display:block;margin-top:8px;font-size:12px;opacity:.78;">Plano do cliente: ${plano} • Status: ${status}</span>
    `;
    grid.appendChild(botao);
  });
}

function renderizarListaClinicasConfiguracao() {
  const box = document.getElementById("listaClinicasConfiguracao");
  if (!box) return;

  const config = obterConfiguracoesSistema();
  const permitidas = vetcoreClinicasPermitidasSeguro();
  const entries = Object.entries((config && config.clinicas) || {}).filter(([chave]) => permitidas.includes(chave));

  if (!entries.length) {
    box.innerHTML = "Nenhuma unidade cadastrada.";
    return;
  }

  const atual = vetcoreSincronizarClinicaDoUsuario();
  const restrito = !!(atual && !vetcoreUsuarioEhMasterSeguro(atual.usuario || ""));

  box.innerHTML = entries.map(([chave, nome]) => `
    <div class="config-list-row">
      <div>
        <strong>${nome}</strong>
        <div class="config-list-meta">Identificador interno: ${chave}</div>
      </div>
      ${restrito ? "" : `<button class="btn-vermelho btn-excluir-agendamento" type="button" onclick="excluirClinica('${chave.replace(/'/g, "\'")}')">Apagar</button>`}
    </div>
  `).join("");
}

function adicionarClinica() {
  const atual = vetcoreSincronizarClinicaDoUsuario ? vetcoreSincronizarClinicaDoUsuario() : null;
  const restrito = !!(atual && !vetcoreUsuarioEhMasterSeguro(atual.usuario || ""));
  const campoChave = document.getElementById("novaClinicaChave");
  const campoNome = document.getElementById("novaClinicaNome");
  const nome = (campoNome?.value || "").trim();
  let chave = (campoChave?.value || "").trim();

  if (!nome) {
    alert("Digite o nome da unidade.");
    return;
  }

  chave = slugClinica(chave || nome);
  if (!chave) {
    alert("Informe um identificador válido para a unidade.");
    return;
  }

  const config = obterConfiguracoesSistema();

  if (restrito) {
    const base = slugClinica(atual.clinicaVinculada || atual.usuario || "cliente");
    const chaveOriginal = chave;
    chave = `${base}-${chaveOriginal}`;
  }

  if ((config.clinicas || {})[chave]) {
    alert("Já existe uma unidade com esse identificador.");
    return;
  }

  config.clinicas[chave] = nome;
  salvarConfiguracoesSistemaStorage(config);

  if (!Array.isArray(veterinariosPorClinica[chave])) {
    veterinariosPorClinica[chave] = [];
    salvarProfissionaisStorage();
  }

  if (restrito && atual && atual.usuario) {
    const usuarios = obterUsuariosPermitidos();
    const emailAtual = (atual.usuario || "").trim().toLowerCase();
    const idx = usuarios.findIndex(u => ((u.usuario || "").trim().toLowerCase() === emailAtual));
    if (idx >= 0) {
      const lista = Array.isArray(usuarios[idx].clinicasVinculadas) ? [...usuarios[idx].clinicasVinculadas] : [];
      if (usuarios[idx].clinicaVinculada && !lista.includes(usuarios[idx].clinicaVinculada)) lista.unshift(usuarios[idx].clinicaVinculada);
      if (!lista.includes(chave)) lista.push(chave);
      usuarios[idx] = { ...usuarios[idx], clinicasVinculadas: lista };
      salvarUsuariosPermitidos(usuarios);
    }

    try {
      const clientes = JSON.parse(localStorage.getItem("vetcoreClientesMestre")) || [];
      const cidx = clientes.findIndex(c =>
        ((c.login || "").trim().toLowerCase() === emailAtual) ||
        ((c.email || "").trim().toLowerCase() === emailAtual)
      );
      if (cidx >= 0) {
        const lista = Array.isArray(clientes[cidx].clinicasVinculadas) ? [...clientes[cidx].clinicasVinculadas] : [];
        if (clientes[cidx].nomeClinica && !lista.includes(clientes[cidx].nomeClinica)) lista.unshift(clientes[cidx].nomeClinica);
        if (!lista.includes(chave)) lista.push(chave);
        clientes[cidx] = { ...clientes[cidx], clinicasVinculadas: lista };
        localStorage.setItem("vetcoreClientesMestre", JSON.stringify(clientes));
      }
    } catch (e) {}
  }

  if (campoChave) campoChave.value = "";
  if (campoNome) campoNome.value = "";

  carregarTelaConfiguracoes();
  alert("Unidade cadastrada com sucesso.");
}

async function excluirClinica(chave) {
  const atual = vetcoreSincronizarClinicaDoUsuario();
  if (atual && !vetcoreUsuarioEhMasterSeguro(atual.usuario || "")) {
    alert("Este usuário não pode excluir unidades por aqui.");
    return;
  }
  if (usuarioLogadoEhClienteRestrito()) {
    alert("Este usuário não pode excluir unidades por aqui.");
    return;
  }
  const config = obterConfiguracoesSistema();
  const entries = Object.keys(config.clinicas || {});

  if (entries.length <= 1) {
    alert("Mantenha pelo menos uma unidade cadastrada.");
    return;
  }

  if (!config.clinicas[chave]) return;
  if (!(await vcConfirm(`Apagar a unidade ${config.clinicas[chave]}?`))) return;

  delete config.clinicas[chave];
  salvarConfiguracoesSistemaStorage(config);

  delete veterinariosPorClinica[chave];
  salvarProfissionaisStorage();

  if (obterClinicaSelecionada() === chave) {
    localStorage.removeItem("clinicaSelecionada");
  }

  carregarTelaConfiguracoes();
  renderizarTelaSelecaoClinicas();
  alert("Unidade apagada com sucesso.");
}

function popularSelectClinicasConfiguracao(selectId, valorSelecionado = "") {
  const select = document.getElementById(selectId);
  if (!select) return;

  const config = obterConfiguracoesSistema();
  const permitidas = vetcoreClinicasPermitidasSeguro();
  const entries = Object.entries((config && config.clinicas) || {}).filter(([chave]) => permitidas.includes(chave));

  select.innerHTML = entries.map(([chave, nome]) => `<option value="${chave}">${nome}</option>`).join("");

  const atual = vetcoreSincronizarClinicaDoUsuario();
  if (atual && !vetcoreUsuarioEhMasterSeguro(atual.usuario || "")) {
    const clinica = localStorage.getItem("clinicaSelecionada") || atual.clinicaVinculada || entries[0]?.[0] || "";
    if (clinica && entries.some(([chave]) => chave === clinica)) {
      select.value = clinica;
    }
    select.disabled = entries.length <= 1;
  } else {
    select.disabled = false;
  }

  if (valorSelecionado && entries.some(([chave]) => chave === valorSelecionado)) {
    select.value = valorSelecionado;
  }
}

function formatarListaTexto(lista) {
  return (Array.isArray(lista) ? lista : []).filter(Boolean).join(", ");
}

function normalizarHorarioTexto(valor) {
  const texto = String(valor || "").trim();
  if (!/^\d{2}:\d{2}$/.test(texto)) return "";
  const [hora, minuto] = texto.split(":").map(Number);
  if (hora < 0 || hora > 23 || minuto < 0 || minuto > 59) return "";
  return `${String(hora).padStart(2, "0")}:${String(minuto).padStart(2, "0")}`;
}

function horarioParaMinutos(valor) {
  const horario = normalizarHorarioTexto(valor);
  if (!horario) return null;
  const [hora, minuto] = horario.split(":").map(Number);
  return (hora * 60) + minuto;
}

function minutosParaHorario(total) {
  const hora = Math.floor(total / 60);
  const minuto = total % 60;
  return `${String(hora).padStart(2, "0")}:${String(minuto).padStart(2, "0")}`;
}

function ordenarHorarios(lista) {
  return [...new Set((Array.isArray(lista) ? lista : []).map(normalizarHorarioTexto).filter(Boolean))]
    .sort((a, b) => horarioParaMinutos(a) - horarioParaMinutos(b));
}

function obterHorariosProfissionalConfiguracao() {
  const input = document.getElementById("profissionalHorarios");
  if (!input) return [];
  return ordenarHorarios((input.value || "").split(",").map(item => item.trim()).filter(Boolean));
}

function definirHorariosProfissionalConfiguracao(lista) {
  const input = document.getElementById("profissionalHorarios");
  if (!input) return;
  input.value = ordenarHorarios(lista).join(", ");
  atualizarPreviewHorariosProfissional();
}

function atualizarPreviewHorariosProfissional() {
  const preview = document.getElementById("horariosPreviewProfissional");
  const horarios = obterHorariosProfissionalConfiguracao();
  if (!preview) return;

  if (!horarios.length) {
    preview.classList.add("vazio");
    preview.innerHTML = "Nenhum horário adicionado ainda.";
    return;
  }

  preview.classList.remove("vazio");
  preview.innerHTML = horarios.map(horario => `
    <span class="horario-chip">
      ${horario}
      <button type="button" onclick="removerHorarioProfissional('${horario}')">&times;</button>
    </span>
  `).join("");
}

function adicionarFaixaHorariosProfissional() {
  const inicio = document.getElementById("profHorarioInicio")?.value || "";
  const fim = document.getElementById("profHorarioFim")?.value || "";
  const intervalo = Number(document.getElementById("profHorarioIntervalo")?.value || 30);

  const inicioMin = horarioParaMinutos(inicio);
  const fimMin = horarioParaMinutos(fim);

  if (inicioMin === null || fimMin === null) {
    alert("Informe o horário inicial e final.");
    return;
  }

  if (fimMin <= inicioMin) {
    alert("O horário final precisa ser maior que o horário inicial.");
    return;
  }

  const faixa = [];
  for (let atual = inicioMin; atual <= fimMin; atual += intervalo) {
    faixa.push(minutosParaHorario(atual));
  }

  definirHorariosProfissionalConfiguracao([
    ...obterHorariosProfissionalConfiguracao(),
    ...faixa
  ]);
}

function adicionarHorarioAvulsoProfissional() {
  const input = document.getElementById("profHorarioAvulso");
  const horario = normalizarHorarioTexto(input?.value || "");

  if (!horario) {
    alert("Escolha um horário válido.");
    return;
  }

  definirHorariosProfissionalConfiguracao([
    ...obterHorariosProfissionalConfiguracao(),
    horario
  ]);

  input.value = "";
}

function removerHorarioProfissional(horario) {
  definirHorariosProfissionalConfiguracao(
    obterHorariosProfissionalConfiguracao().filter(item => item !== horario)
  );
}

function limparHorariosProfissional() {
  definirHorariosProfissionalConfiguracao([]);
}


function obterServicosBaseProfissionalConfiguracao(clinica = "") {
  const padrao = [
    "Consulta",
    "Vacina",
    "Retorno",
    "Castração",
    "Exames",
    "Banho e Tosa",
    "Procedimento",
    "Emergência"
  ];

  const cadastrados = [];

  Object.values(veterinariosPorClinica || {}).forEach(lista => {
    (lista || []).forEach(vet => {
      (vet.procedimentos || []).forEach(servico => cadastrados.push(servico));
    });
  });

  if (clinica && veterinariosPorClinica[clinica]) {
    (veterinariosPorClinica[clinica] || []).forEach(vet => {
      (vet.procedimentos || []).forEach(servico => cadastrados.push(servico));
    });
  }

  try {
    const extras = JSON.parse(localStorage.getItem("vetcoreServicosPadrao") || "[]");
    if (Array.isArray(extras)) extras.forEach(servico => cadastrados.push(servico));
  } catch (e) {}

  return [...padrao, ...cadastrados]
    .map(item => String(item || "").trim())
    .filter(Boolean)
    .filter((item, index, arr) => arr.findIndex(outro => normalizar(outro) === normalizar(item)) === index)
    .sort((a, b) => a.localeCompare(b, "pt-BR"));
}

function renderizarServicosProfissionalConfiguracao(servicosSelecionados = []) {
  const box = document.getElementById("profissionalServicosLista");
  if (!box) return;

  const clinica = document.getElementById("profissionalClinica")?.value || "";
  const servicos = obterServicosBaseProfissionalConfiguracao(clinica);
  const selecionados = (servicosSelecionados || []).map(item => normalizar(item));

  if (!servicos.length) {
    box.innerHTML = "<div class='subinfo'>Nenhum serviço disponível.</div>";
    return;
  }

  box.innerHTML = servicos.map(servico => {
    const marcado = selecionados.includes(normalizar(servico)) ? "checked" : "";
    const seguro = String(servico).replace(/&/g, "&amp;").replace(/</g, "&lt;").replace(/>/g, "&gt;").replace(/\"/g, "&quot;");
    return `
      <label class="servico-check-card">
        <input type="checkbox" class="profissional-servico-check" value="${seguro}" ${marcado}>
        <span>${seguro}</span>
      </label>
    `;
  }).join("");
}

function obterServicosSelecionadosProfissionalConfiguracao() {
  const checks = [...document.querySelectorAll(".profissional-servico-check:checked")]
    .map(input => input.value.trim())
    .filter(Boolean);

  const extra = document.getElementById("profissionalServicoExtra")?.value || "";
  const extras = extra.split(",").map(item => item.trim()).filter(Boolean);

  return [...checks, ...extras]
    .filter((item, index, arr) => arr.findIndex(outro => normalizar(outro) === normalizar(item)) === index);
}

function obterDiasSelecionadosProfissionalConfiguracao() {
  return [...document.querySelectorAll(".profissional-dia-check:checked")]
    .map(input => Number(input.value))
    .filter(dia => !Number.isNaN(dia));
}

function limparDiasProfissionalConfiguracao() {
  document.querySelectorAll(".profissional-dia-check").forEach(input => {
    input.checked = false;
  });
}

function salvarDiasProfissionalComoLiberacao(clinica, nomeProfissional, servicos, dias) {
  if (!clinica || !nomeProfissional || !Array.isArray(servicos) || !Array.isArray(dias)) return;
  const liberacoes = obterLiberacoes();
  servicos.forEach(servico => {
    const chave = obterChaveLiberacao(clinica, nomeProfissional, servico);
    liberacoes[chave] = dias;
  });
  localStorage.setItem("diasLiberados", JSON.stringify(liberacoes));
}

function renderizarListaProfissionaisConfiguracao() {
  const box = document.getElementById("listaProfissionaisConfiguracao");
  const filtro = document.getElementById("filtroProfissionaisClinica");
  if (!box || !filtro) return;

  popularSelectClinicasConfiguracao("filtroProfissionaisClinica", filtro.value);
  const clinica = filtro.value || obterTodasAsClinicasDisponiveis()[0];
  if (clinica) filtro.value = clinica;

  const lista = veterinariosPorClinica[clinica] || [];
  if (!lista.length) {
    box.innerHTML = "Nenhum profissional cadastrado para essa clínica.";
    return;
  }

  const clinicaParam = encodeURIComponent(clinica);

  box.innerHTML = lista.map((item, index) => `
    <div class="config-list-row config-list-row-stacked">
      <div>
        <strong>${escaparHtmlVetCore(item.nome)}</strong>
        <div class="config-list-meta">Serviços: ${escaparHtmlVetCore(formatarListaTexto(item.procedimentos))}</div>
        <div class="config-list-meta">Dias: ${Array.isArray(item.diasAtendimento) && item.diasAtendimento.length ? item.diasAtendimento.map(diaNome).join(", ") : "Não definido"}</div>
        <div class="config-list-meta">Horários: ${escaparHtmlVetCore(formatarListaTexto(item.horariosArray) || item.horarios || "Padrão")}</div>
      </div>
      <div class="config-list-actions">
        <button class="btn-secundario btn-excluir-agendamento" type="button" onclick="abrirModalEditarProfissional('${clinicaParam}', ${index})">Editar</button>
        <button class="btn-vermelho btn-excluir-agendamento" type="button" onclick="excluirProfissional('${clinicaParam}', ${index})">Apagar</button>
      </div>
    </div>
  `).join("");
}

function escaparHtmlVetCore(valor) {
  return String(valor ?? "")
    .replace(/&/g, "&amp;")
    .replace(/</g, "&lt;")
    .replace(/>/g, "&gt;")
    .replace(/\"/g, "&quot;")
    .replace(/'/g, "&#039;");
}

function fecharModalEditarProfissional() {
  const modal = document.getElementById("modalEditarProfissionalVetCore");
  if (modal) modal.remove();
}

function obterServicosSelecionadosModalEditarProfissional() {
  const checks = [...document.querySelectorAll(".editar-profissional-servico-check:checked")]
    .map(input => input.value.trim())
    .filter(Boolean);
  const extra = document.getElementById("editarProfissionalServicoExtra")?.value || "";
  const extras = extra.split(",").map(item => item.trim()).filter(Boolean);
  return [...checks, ...extras]
    .filter((item, index, arr) => arr.findIndex(outro => normalizar(outro) === normalizar(item)) === index);
}

function obterDiasSelecionadosModalEditarProfissional() {
  return [...document.querySelectorAll(".editar-profissional-dia-check:checked")]
    .map(input => Number(input.value))
    .filter(dia => !Number.isNaN(dia));
}

function obterHorariosModalEditarProfissional() {
  const texto = document.getElementById("editarProfissionalHorarios")?.value || "";
  return texto
    .split(/[,;\n]/)
    .map(item => normalizarHorarioTexto(item.trim()))
    .filter(Boolean)
    .filter((item, index, arr) => arr.indexOf(item) === index)
    .sort((a, b) => horarioParaMinutos(a) - horarioParaMinutos(b));
}

function abrirModalEditarProfissional(clinicaCodificada, index) {
  const clinica = decodeURIComponent(clinicaCodificada || "");
  const lista = veterinariosPorClinica[clinica] || [];
  const item = lista[index];
  if (!item) return;

  fecharModalEditarProfissional();

  const servicosBase = obterServicosBaseProfissionalConfiguracao(clinica);
  const selecionados = (item.procedimentos || []).map(servico => normalizar(servico));
  const horarios = Array.isArray(item.horariosArray) && item.horariosArray.length
    ? item.horariosArray
    : String(item.horarios || "").split(",").map(h => h.trim()).filter(Boolean);
  const diasSelecionados = Array.isArray(item.diasAtendimento) ? item.diasAtendimento.map(Number) : [];

  const modal = document.createElement("div");
  modal.id = "modalEditarProfissionalVetCore";
  modal.className = "vetcore-modal-sistema";
  modal.innerHTML = `
    <div class="vetcore-modal-card vetcore-modal-card-grande" role="dialog" aria-modal="true">
      <div class="vetcore-modal-icone">✎</div>
      <h3>Editar profissional</h3>
      <div class="vetcore-modal-mensagem">Altere os dados do profissional, serviços, dias de atendimento e horários.</div>

      <div class="editar-profissional-grid">
        <label>
          <span>Clínica</span>
          <input type="text" value="${escaparHtmlVetCore(clinica)}" disabled>
        </label>
        <label>
          <span>Nome do profissional</span>
          <input type="text" id="editarProfissionalNome" value="${escaparHtmlVetCore(item.nome || "")}">
        </label>
      </div>

      <div class="editar-profissional-secao">
        <strong>Serviços atendidos</strong>
        <div class="servicos-checkbox-grid editar-profissional-servicos">
          ${servicosBase.map(servico => {
            const marcado = selecionados.includes(normalizar(servico)) ? "checked" : "";
            return `<label class="servico-check-card"><input type="checkbox" class="editar-profissional-servico-check" value="${escaparHtmlVetCore(servico)}" ${marcado}><span>${escaparHtmlVetCore(servico)}</span></label>`;
          }).join("")}
        </div>
        <input type="text" id="editarProfissionalServicoExtra" placeholder="Adicionar serviço extra separado por vírgula">
      </div>

      <div class="editar-profissional-secao">
        <strong>Dias de atendimento</strong>
        <div class="dias-grid dias-grid-profissional editar-profissional-dias">
          ${[1,2,3,4,5,6,0].map(dia => `<label class="dia-item"><input type="checkbox" class="editar-profissional-dia-check" value="${dia}" ${diasSelecionados.includes(dia) ? "checked" : ""}> ${diaNome(dia)}</label>`).join("")}
        </div>
      </div>

      <div class="editar-profissional-secao">
        <strong>Horários</strong>
        <textarea id="editarProfissionalHorarios" rows="4" placeholder="Ex: 09:00, 09:30, 10:00">${escaparHtmlVetCore(horarios.join(", "))}</textarea>
        <div class="subinfo config-subinfo-left">Separe os horários por vírgula ou quebra de linha.</div>
      </div>

      <div class="vetcore-modal-acoes">
        <button type="button" class="btn-secundario" onclick="fecharModalEditarProfissional()">Cancelar</button>
        <button type="button" class="btn-verde" onclick="salvarEdicaoProfissional('${clinicaCodificada}', ${index})">Salvar alterações</button>
      </div>
    </div>
  `;
  document.body.appendChild(modal);
  setTimeout(() => document.getElementById("editarProfissionalNome")?.focus(), 80);
}

async function salvarEdicaoProfissional(clinicaCodificada, index) {
  const clinica = decodeURIComponent(clinicaCodificada || "");
  const lista = veterinariosPorClinica[clinica] || [];
  const itemAtual = lista[index];
  if (!itemAtual) return;

  const nome = document.getElementById("editarProfissionalNome")?.value.trim() || "";
  const servicos = obterServicosSelecionadosModalEditarProfissional();
  const diasAtendimento = obterDiasSelecionadosModalEditarProfissional();
  const horariosArray = obterHorariosModalEditarProfissional();

  if (!nome) return alert("Digite o nome do profissional.");
  if (!servicos.length) return alert("Informe pelo menos um serviço.");
  if (!diasAtendimento.length) return alert("Informe pelo menos um dia de atendimento.");
  if (!horariosArray.length) return alert("Informe pelo menos um horário válido.");

  const existe = lista.some((item, i) => i !== index && normalizar(item.nome) === normalizar(nome));
  if (existe) return alert("Já existe outro profissional com esse nome nessa clínica.");

  lista[index] = {
    ...itemAtual,
    nome,
    procedimentos: servicos,
    horarios: horariosArray.join(", "),
    horariosArray,
    diasAtendimento
  };

  veterinariosPorClinica[clinica] = lista;
  salvarProfissionaisStorage();
  salvarDiasProfissionalComoLiberacao(clinica, nome, servicos, diasAtendimento);
  fecharModalEditarProfissional();
  popularSelectClinicasConfiguracao("filtroProfissionaisClinica", clinica);
  renderizarListaProfissionaisConfiguracao();
  alert("Profissional atualizado com sucesso.");
}

function adicionarProfissional() {
  const clinica = document.getElementById("profissionalClinica")?.value || "";
  const nome = document.getElementById("profissionalNome")?.value.trim() || "";
  const horariosArray = obterHorariosProfissionalConfiguracao();

  if (!clinica) {
    alert("Selecione a clínica.");
    return;
  }

  if (!nome) {
    alert("Digite o nome do profissional.");
    return;
  }

  const servicos = obterServicosSelecionadosProfissionalConfiguracao();

  if (!servicos.length) {
    alert("Informe pelo menos um serviço.");
    return;
  }

  if (!horariosArray.length) {
    alert("Informe pelo menos um horário.");
    return;
  }

  const diasAtendimento = obterDiasSelecionadosProfissionalConfiguracao();

  if (!diasAtendimento.length) {
    alert("Informe pelo menos um dia de atendimento do profissional.");
    return;
  }

  const lista = veterinariosPorClinica[clinica] || [];
  const existe = lista.some(item => normalizar(item.nome) === normalizar(nome));
  if (existe) {
    alert("Já existe um profissional com esse nome nessa clínica.");
    return;
  }

  lista.push({
    nome,
    procedimentos: servicos,
    horarios: horariosArray.join(", "),
    horariosArray,
    diasAtendimento
  });

  veterinariosPorClinica[clinica] = lista;
  salvarProfissionaisStorage();
  salvarDiasProfissionalComoLiberacao(clinica, nome, servicos, diasAtendimento);

  document.getElementById("profissionalNome").value = "";
  const campoExtraServico = document.getElementById("profissionalServicoExtra");
  if (campoExtraServico) campoExtraServico.value = "";
  document.getElementById("profHorarioAvulso").value = "";
  limparDiasProfissionalConfiguracao();
  renderizarServicosProfissionalConfiguracao();
  definirHorariosProfissionalConfiguracao([]);
  popularSelectClinicasConfiguracao("filtroProfissionaisClinica", clinica);
  renderizarListaProfissionaisConfiguracao();

  alert("Profissional cadastrado com sucesso.");
}

async function excluirProfissional(clinica, index) {
  clinica = decodeURIComponent(clinica || "");
  const lista = veterinariosPorClinica[clinica] || [];
  const item = lista[index];
  if (!item) return;

  if (!(await vcConfirm(`Apagar o profissional ${item.nome}?`))) return;

  lista.splice(index, 1);
  veterinariosPorClinica[clinica] = lista;
  salvarProfissionaisStorage();
  popularSelectClinicasConfiguracao("filtroProfissionaisClinica", clinica);
  renderizarListaProfissionaisConfiguracao();
  alert("Profissional apagado com sucesso.");
}


