function carregarExcecaoAgendaAtual() {
  const clinica = obterClinicaSelecionada();
  const vetNome = document.getElementById("extraVet").value;
  const servico = document.getElementById("extraServico").value;
  const dataIso = document.getElementById("extraData").value;

  if (!vetNome || !servico || !dataIso) {
    document.getElementById("extraTipo").value = "";
    document.getElementById("configAgendaExtraAtual").innerText = "Selecione veterinário, serviço e data para ver a configuração.";
    return;
  }

  const excecoes = obterExcecoesAgenda();
  const chave = obterChaveExcecaoAgenda(clinica, vetNome, servico, dataIso);
  const atual = excecoes[chave] || "normal";

  document.getElementById("extraTipo").value = atual;

  let texto = "Seguindo regra normal.";
  if (atual === "abrir") texto = "Atendimento extra liberado nesta data.";
  if (atual === "fechar") texto = "Atendimento fechado nesta data.";

  document.getElementById("configAgendaExtraAtual").innerHTML =
    `<strong>Configuração atual:</strong><br>${vetNome} | ${servico} | ${formatarData(dataIso)}<br>${texto}`;
}

function salvarExcecaoAgenda() {
  const clinica = obterClinicaSelecionada();
  const vetNome = document.getElementById("extraVet").value;
  const servico = document.getElementById("extraServico").value;
  const dataIso = document.getElementById("extraData").value;
  const tipo = document.getElementById("extraTipo").value;

  if (!vetNome || !servico || !dataIso || !tipo) {
    alert("Escolha o veterinário, o serviço, a data e a ação.");
    return;
  }

  const excecoes = obterExcecoesAgenda();
  const chave = obterChaveExcecaoAgenda(clinica, vetNome, servico, dataIso);

  if (tipo === "normal") {
    delete excecoes[chave];
  } else {
    excecoes[chave] = tipo;
  }

  localStorage.setItem("excecoesAgenda", JSON.stringify(excecoes));
  carregarExcecaoAgendaAtual();
  alert("Exceção de agenda salva com sucesso.");
}


