function aoMudarVetRecorrente() {
  const clinica = obterClinicaSelecionada();
  const vetNome = document.getElementById("recVet").value;
  const selectServico = document.getElementById("recServico");

  selectServico.innerHTML = '<option value="">Escolha o serviço</option>';
  document.getElementById("recDiaSemana").value = "";
  document.getElementById("recDiaInteiro").checked = false;
  document.getElementById("horariosRecorrentesContainer").innerHTML = "";
  document.getElementById("configRecorrenteAtual").innerText = "Agora escolha o serviço e o dia da semana.";

  if (!vetNome) return;

  const vets = veterinariosPorClinica[clinica] || [];
  const vet = vets.find(v => v.nome === vetNome);

  obterProcedimentosVetComRetorno(vet).forEach(servico => {
    const option = document.createElement("option");
    option.value = servico;
    option.textContent = servico;
    selectServico.appendChild(option);
  });
}

function aoMudarServicoRecorrente() {
  document.getElementById("recDiaSemana").value = "";
  document.getElementById("recDiaInteiro").checked = false;
  document.getElementById("horariosRecorrentesContainer").innerHTML = "";
  document.getElementById("configRecorrenteAtual").innerText = "Agora escolha o dia da semana.";
}

function aoMudarDiaRecorrente() {
  const clinica = obterClinicaSelecionada();
  const vetNome = document.getElementById("recVet").value;
  const servico = document.getElementById("recServico").value;
  const diaSemana = document.getElementById("recDiaSemana").value;

  if (!vetNome || !servico || diaSemana === "") {
    document.getElementById("recDiaInteiro").checked = false;
    document.getElementById("horariosRecorrentesContainer").innerHTML = "";
    document.getElementById("configRecorrenteAtual").innerText = "Selecione veterinário, serviço e dia da semana para ver a configuração.";
    return;
  }

  montarRecorrente(clinica, vetNome, servico, Number(diaSemana));
}

function montarRecorrente(clinica, vetNome, servico, diaSemana) {
  const container = document.getElementById("horariosRecorrentesContainer");
  container.innerHTML = "";

  const horariosBase = obterHorariosBaseDoVeterinario(vetNome, servico);
  const recorrentes = obterFechamentosRecorrentes();
  const chave = obterChaveFechamentoRecorrente(clinica, vetNome, servico, diaSemana);
  const registro = recorrentes[chave] || { diaInteiro: false, horas: [] };
  const fechados = registro.horas || [];
  const diaInteiro = registro.diaInteiro === true;

  document.getElementById("recDiaInteiro").checked = diaInteiro;

  if (!horariosBase.length) {
    container.innerHTML = '<div class="vazio">Esse veterinário não possui grade de horários cadastrada.</div>';
    document.getElementById("configRecorrenteAtual").innerHTML =
      `<strong>${vetNome}</strong> | ${servico} | ${diaNome(diaSemana)}<br>Sem horários cadastrados.`;
    return;
  }

  horariosBase.forEach(hora => {
    const label = document.createElement("label");
    label.className = "hora-item";
    label.innerHTML = `<input type="checkbox" value="${hora}" ${fechados.includes(hora) ? "checked" : ""}> ${hora}`;
    container.appendChild(label);
  });

  alternarRecorrenteDiaInteiro();

  let texto = "Nenhum horário bloqueado.";
  if (diaInteiro) {
    texto = "Dia inteiro bloqueado.";
  } else if (fechados.length) {
    texto = fechados.join(", ");
  }

  document.getElementById("configRecorrenteAtual").innerHTML =
    `<strong>Configuração atual:</strong><br>${vetNome} | ${servico} | ${diaNome(diaSemana)}<br>${texto}`;
}

function alternarRecorrenteDiaInteiro() {
  const diaInteiro = document.getElementById("recDiaInteiro").checked;
  const checkboxes = document.querySelectorAll("#horariosRecorrentesContainer input[type='checkbox']");
  checkboxes.forEach(cb => {
    cb.disabled = diaInteiro;
  });
}

function salvarHorariosRecorrentes() {
  const clinica = obterClinicaSelecionada();
  const vetNome = document.getElementById("recVet").value;
  const servico = document.getElementById("recServico").value;
  const diaSemana = document.getElementById("recDiaSemana").value;
  const diaInteiro = document.getElementById("recDiaInteiro").checked;

  if (!vetNome || !servico || diaSemana === "") {
    alert("Escolha o veterinário, o serviço e o dia da semana.");
    return;
  }

  const selecionados = Array.from(document.querySelectorAll("#horariosRecorrentesContainer input[type='checkbox']:checked"))
    .map(el => el.value);

  const recorrentes = obterFechamentosRecorrentes();
  const chave = obterChaveFechamentoRecorrente(clinica, vetNome, servico, Number(diaSemana));

  recorrentes[chave] = {
    diaInteiro: diaInteiro,
    horas: diaInteiro ? [] : selecionados
  };

  localStorage.setItem("horariosFechadosRecorrentes", JSON.stringify(recorrentes));

  montarRecorrente(clinica, vetNome, servico, Number(diaSemana));
  alert("Bloqueio recorrente salvo com sucesso.");
}

