function obterStatusHorario(clinica, vetNome, servicoFiltro, dataFiltro, horario) {
  const agendamentos = obterAgendamentos().filter(item =>
    item.clinica === clinica &&
    item.veterinario === vetNome &&
    item.data === dataFiltro &&
    item.horario === horario
  );

  const haAgendamentoFiltrado = agendamentos.find(item => {
    if (servicoFiltro === "Todos") return normalizarServico(item.servico) !== "castracao";
    return normalizarServico(item.servico) === normalizarServico(servicoFiltro);
  });

  if (haAgendamentoFiltrado) {
    return { status: "agendado", agendamento: haAgendamentoFiltrado };
  }

  const servicoReferencia = servicoFiltro === "Todos" ? "Consulta" : servicoFiltro;
  const fechamentos = obterFechamentosData();
  const chave = obterChaveFechamentoData(clinica, vetNome, servicoReferencia, dataFiltro);
  const registro = fechamentos[chave] || { diaInteiro: false, horas: [] };

  const diaSemana = diaSemanaDaData(dataFiltro);
  const recorrentes = obterFechamentosRecorrentes();
  const chaveRec = obterChaveFechamentoRecorrente(clinica, vetNome, servicoReferencia, diaSemana);
  const registroRec = recorrentes[chaveRec] || { diaInteiro: false, horas: [] };

  if (
    registro.diaInteiro ||
    (registro.horas || []).includes(horario) ||
    registroRec.diaInteiro ||
    (registroRec.horas || []).includes(horario)
  ) {
    return { status: "fechado", agendamento: null };
  }

  return { status: "livre", agendamento: null };
}

function carregarListaAgendamentos() {
  const dataFiltro = document.getElementById("filtroDataLista").value;
  const servicoFiltro = document.getElementById("filtroServicoLista").value;
  const vetFiltro = document.getElementById("filtroVeterinarioLista").value;
  const clinicaSelecionada = obterClinicaSelecionada();

  const container = document.getElementById("listaAgendamentos");
  const resumo = document.getElementById("resumoDia");
  container.innerHTML = "";

  if (!dataFiltro) {
    resumo.classList.add("oculto");
    container.innerHTML = '<div class="vazio">Escolha uma data para visualizar os agendamentos.</div>';
    return;
  }

  const lista = obterAgendamentos();
  const filtrados = lista.filter(item => {
    const bateClinica = item.clinica === clinicaSelecionada;
    const bateData = item.data === dataFiltro;
    const bateServico = servicoFiltro === "Todos" ? true : normalizarServico(item.servico) === normalizarServico(servicoFiltro);
    const bateVet = vetFiltro === "Todos" ? true : item.veterinario === vetFiltro;
    return bateClinica && bateData && bateServico && bateVet;
  });

  const felinoMacho = filtrados.filter(item => normalizar(item.especie) === "felino" && normalizar(item.sexo) === "macho");
  const felinoFemea = filtrados.filter(item => normalizar(item.especie) === "felino" && normalizar(item.sexo) === "femea");
  const caninoMacho = filtrados.filter(item => normalizar(item.especie) === "canino" && normalizar(item.sexo) === "macho");
  const caninoFemea = filtrados.filter(item => normalizar(item.especie) === "canino" && normalizar(item.sexo) === "femea");

  document.getElementById("totalDia").innerText = filtrados.length;
  document.getElementById("totalFelinos").innerText = felinoMacho.length + felinoFemea.length;
  document.getElementById("totalCaninos").innerText = caninoMacho.length + caninoFemea.length;
  document.getElementById("totalMachos").innerText = felinoMacho.length + caninoMacho.length;
  document.getElementById("totalFemeas").innerText = felinoFemea.length + caninoFemea.length;
  resumo.classList.remove("oculto");

  const vets = (veterinariosPorClinica[clinicaSelecionada] || []).filter(vet => vetFiltro === "Todos" ? true : vet.nome === vetFiltro);

  if (servicoFiltro !== "Castração" && !servicoEhProcedimentoComNome(servicoFiltro)) {
    vets.forEach(vet => {
      const procedimentos = (vet.procedimentos || []).map(normalizarServico);
      const podeMostrar = servicoFiltro === "Todos"
        ? procedimentos.some(p => ["consulta", "vacina", "retorno", "consulta", "vacina"].includes(p))
        : procedimentos.some(p => ["consulta", "vacina", "retorno"].includes(normalizarServico(servicoFiltro)) ? ["consulta", "vacina", "retorno"].includes(p) : p === normalizarServico(servicoFiltro));

      if (!podeMostrar) return;

      const horarios = obterHorariosBaseDoVeterinario(vet.nome, servicoFiltro === "Todos" ? "Todos" : servicoFiltro);
      const linhas = horarios.map(horario => {
        const info = obterStatusHorario(clinicaSelecionada, vet.nome, servicoFiltro, dataFiltro, horario);
        return criarLinhaAgendaStatus(horario, info.status, info.agendamento, vet.nome, servicoFiltro, dataFiltro);
      });

      container.appendChild(criarSecaoAgendaVet(vet.nome, linhas));
    });
  }

  const castracoes = lista
    .filter(item =>
      item.clinica === clinicaSelecionada &&
      item.data === dataFiltro &&
      normalizarServico(item.servico) === "castracao" &&
      (servicoFiltro === "Todos" || normalizarServico(servicoFiltro) === "castracao") &&
      (vetFiltro === "Todos" || item.veterinario === vetFiltro)
    )
    .sort((a, b) => (a.horario || "").localeCompare(b.horario || ""));

  if (castracoes.length) {
    container.appendChild(criarSecaoTabelaCastracao("Castrações", castracoes));
  }

  // VetCore ajuste: quando o filtro for Procedimento/Cirurgia, mostrar a agenda
  // como janela fixa por veterinário, mesmo antes de existir agendamento salvo.
  // Antes o serviço aparecia no filtro, mas a grade ficava vazia porque
  // procedimentos não entram na agenda de horários normais.
  if (servicoEhProcedimentoComNome(servicoFiltro)) {
    vets.forEach(vet => {
      const servicosVet = obterProcedimentosVetComRetorno(vet);
      const possuiServico = servicosVet.some(s => normalizarServico(s) === normalizarServico(servicoFiltro));
      if (!possuiServico) return;

      const horarios = obterHorariosBaseDoVeterinario(vet.nome, servicoFiltro);
      const linhas = horarios.map(horario => {
        const info = obterStatusHorario(clinicaSelecionada, vet.nome, servicoFiltro, dataFiltro, horario);
        return criarLinhaAgendaStatus(horario, info.status, info.agendamento, vet.nome, servicoFiltro, dataFiltro);
      });

      if (linhas.length) {
        container.appendChild(criarSecaoAgendaVet(`${vet.nome} — ${servicoFiltro}`, linhas));
      }
    });
  }

  const procedimentosAgenda = lista
    .filter(item =>
      item.clinica === clinicaSelecionada &&
      item.data === dataFiltro &&
      servicoEhProcedimentoComNome(item.servico) &&
      (servicoFiltro === "Todos" || normalizarServico(item.servico) === normalizarServico(servicoFiltro)) &&
      (vetFiltro === "Todos" || item.veterinario === vetFiltro)
    )
    .sort((a, b) => (a.horario || "").localeCompare(b.horario || ""));

  if (procedimentosAgenda.length && !servicoEhProcedimentoComNome(servicoFiltro)) {
    container.appendChild(criarSecaoTabelaCastracao("Procedimentos / Cirurgias", procedimentosAgenda));
  }

  if (!container.innerHTML.trim()) {
    container.innerHTML = '<div class="vazio">Nenhum agendamento encontrado para essa data.</div>';
  }
}

async function excluirAgendamento(id) {
  if (!temPermissao("excluirAgendamento")) { alert("Você não tem permissão para excluir agendamentos."); return; }
  const confirmar = await vcConfirm("Tem certeza que deseja excluir este agendamento?");
  if (!confirmar) return;

  const novaLista = obterAgendamentos().filter(item => item.id !== id);
  salvarAgendamentos(novaLista);

  alert("Agendamento excluído com sucesso.");
  atualizarMenu();
  carregarListaAgendamentos();
}

