            const l=[]; Array.from(hs).filter(Boolean).sort().slice(0,80).forEach(h=>{ if(linhas>=limite)return; const ags=getIdx(idx,nome,h,'Retorno'); if(ags.length) ags.forEach(ag=>{l.push(linha(h,'agendado','Retorno',nome,data,ag)); linhas++;}); else {l.push(linha(h,'livre','Retorno',nome,data,null)); livres++; linhas++;} });
