  window.abrirVisualizacao = (function(base){ return function(){ try{ if(typeof mostrarTela==='function') mostrarTela('telaVisualizar'); else if(base) base(); }catch(e){ if(base) base(); } setTimeout(()=>{ const d=$('filtroDataLista'); if(d&&!d.value) d.value=hojeIso(); if(d) d.value=isoData(d.value||hojeIso()); try{ if(typeof preencherFiltroVeterinario==='function') preencherFiltroVeterinario(); }catch(e){} const info=$('infoVisualizacao'); if(info) info.innerText='Clínica: '+clinicaAtualSafe(); window.carregarListaAgendamentos(); },80); }; })(window.abrirVisualizacao);
