    arr(vet.servicosAgenda).forEach(x=>out.push((x&&(x.servico||x.nome||x.tipo))||x));
    if(vet.horariosPorServico) Object.keys(vet.horariosPorServico).forEach(k=>out.push(k));
    if(vet.gradeServicos) Object.keys(vet.gradeServicos).forEach(k=>out.push(k));
