    for(const k of Object.keys(mapa)){ const kg=grupo(k); const match=kg===alvo || (alvo==='consulta_vacina' && (isConsulta(k)||isVacina(k))); if(match && arr(mapa[k]).map(Number).includes(dia)) return true; }
    const l=libs();
