  function hm(x){ return String(Math.floor(x/60)).padStart(2,'0')+':'+String(x%60).padStart(2,'0'); }
  function gerar(ini,fim,tempo){ const a=min(ini), b=min(fim), t=Number(tempo||30), out=[]; if(a==null||b==null||!t||b<a) return out; for(let x=a;x<=b&&out.length<80;x+=t) out.push(hm(x)); return out; }
