    if(!set.size && isRetorno(servico)){ if(['dra. bruna','dr. rafael','dra bruna','dr rafael'].includes(norm(vet.nome))) ['09:05','10:05','11:05','14:05','15:05','16:05','17:05'].forEach(h=>set.add(h)); }
